package com.maum.backend.service

import com.maum.backend.domain.call.CallEntity
import com.maum.backend.domain.call.CallRepository
import com.maum.backend.domain.call.CallStatus
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.`when`
import org.mockito.Mockito.verify
import org.mockito.junit.jupiter.MockitoExtension
import java.util.*

@ExtendWith(MockitoExtension::class)
class CallServiceTest {

    @Mock
    private lateinit var callRepository: CallRepository

    @InjectMocks
    private lateinit var callService: CallService

    // ────────────────────────────────────────────
    // initiateCall
    // ────────────────────────────────────────────

    @Test
    fun `should initiate call successfully when caller and receiver are valid`() {
        // given
        val callerId = "user-A"
        val receiverId = "user-B"
        val savedCall = CallEntity(id = "call-1", callerId = callerId, receiverId = receiverId)

        `when`(callRepository.findActiveCallsByUserId(callerId)).thenReturn(emptyList())
        `when`(callRepository.save(org.mockito.kotlin.any())).thenReturn(savedCall)

        // when
        val result = callService.initiateCall(callerId, receiverId)

        // then
        assertThat(result.callerId).isEqualTo(callerId)
        assertThat(result.receiverId).isEqualTo(receiverId)
        assertThat(result.status).isEqualTo(CallStatus.WAITING)
        verify(callRepository).findActiveCallsByUserId(callerId)
        verify(callRepository).save(org.mockito.kotlin.any())
    }

    @Test
    fun `should throw when caller is blank`() {
        // when & then
        assertThrows<IllegalArgumentException> {
            callService.initiateCall("", "user-B")
        }
    }

    @Test
    fun `should throw when receiver is blank`() {
        // when & then
        assertThrows<IllegalArgumentException> {
            callService.initiateCall("user-A", "")
        }
    }

    @Test
    fun `should throw when caller tries to call themselves`() {
        // when & then
        val ex = assertThrows<IllegalArgumentException> {
            callService.initiateCall("user-A", "user-A")
        }
        assertThat(ex.message).contains("자기 자신")
    }

    @Test
    fun `should throw when caller already has an active call`() {
        // given
        val callerId = "user-A"
        val existingCall = CallEntity(id = "existing-1", callerId = callerId, receiverId = "user-C", status = CallStatus.ACTIVE)

        `when`(callRepository.findActiveCallsByUserId(callerId)).thenReturn(listOf(existingCall))

        // when & then
        val ex = assertThrows<IllegalStateException> {
            callService.initiateCall(callerId, "user-B")
        }
        assertThat(ex.message).contains("이미 진행 중인 통화")
    }

    // ────────────────────────────────────────────
    // acceptCall
    // ────────────────────────────────────────────

    @Test
    fun `should accept call when receiver calls acceptCall`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val call = CallEntity(id = callId, callerId = "user-A", receiverId = receiverId, status = CallStatus.WAITING)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))
        `when`(callRepository.save(call)).thenReturn(call)

        // when
        val result = callService.acceptCall(callId, receiverId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.ACTIVE)
        assertThat(result.startedAt).isNotNull()
    }

    @Test
    fun `should throw when non-receiver tries to accept call`() {
        // given
        val callId = "call-1"
        val call = CallEntity(id = callId, callerId = "user-A", receiverId = "user-B", status = CallStatus.WAITING)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))

        // when & then
        val ex = assertThrows<IllegalArgumentException> {
            callService.acceptCall(callId, "user-C") // 통화 참여자가 아닌 사용자
        }
        assertThat(ex.message).contains("수신자만")
    }

    @Test
    fun `should throw when accepting already active call`() {
        // given
        val callId = "call-1"
        val call = CallEntity(id = callId, callerId = "user-A", receiverId = "user-B", status = CallStatus.ACTIVE)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))

        // when & then
        // ACTIVE 상태의 통화를 다시 start() 하면 IllegalStateException 발생 (버그 재현)
        assertThrows<IllegalStateException> {
            callService.acceptCall(callId, "user-B")
        }
    }

    @Test
    fun `should throw when call not found on accept`() {
        // given
        `when`(callRepository.findById("not-exist")).thenReturn(Optional.empty())

        // when & then
        assertThrows<NoSuchElementException> {
            callService.acceptCall("not-exist", "user-B")
        }
    }

    // ────────────────────────────────────────────
    // endCall
    // ────────────────────────────────────────────

    @Test
    fun `should end call when caller ends active call`() {
        // given
        val callId = "call-1"
        val callerId = "user-A"
        val call = CallEntity(id = callId, callerId = callerId, receiverId = "user-B", status = CallStatus.ACTIVE)
        call.start() // startedAt 세팅

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))
        `when`(callRepository.save(call)).thenReturn(call)

        // when
        val result = callService.endCall(callId, callerId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.ENDED)
        assertThat(result.endedAt).isNotNull()
    }

    @Test
    fun `should end call when receiver ends active call`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val call = CallEntity(id = callId, callerId = "user-A", receiverId = receiverId, status = CallStatus.ACTIVE)
        call.start()

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))
        `when`(callRepository.save(call)).thenReturn(call)

        // when
        val result = callService.endCall(callId, receiverId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.ENDED)
    }

    @Test
    fun `should throw when non-participant tries to end call`() {
        // given
        val callId = "call-1"
        val call = CallEntity(id = callId, callerId = "user-A", receiverId = "user-B", status = CallStatus.ACTIVE)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))

        // when & then
        val ex = assertThrows<IllegalArgumentException> {
            callService.endCall(callId, "user-C")
        }
        assertThat(ex.message).contains("통화 참여자만")
    }

    @Test
    fun `should throw when ending a call that is not active`() {
        // given
        val callId = "call-1"
        val call = CallEntity(id = callId, callerId = "user-A", receiverId = "user-B", status = CallStatus.ENDED)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))

        // when & then
        // 이미 종료된 통화를 종료하면 IllegalStateException 발생 (버그 재현: 중복 종료 처리)
        assertThrows<IllegalStateException> {
            callService.endCall(callId, "user-A")
        }
    }

    @Test
    fun `should throw when call not found on end`() {
        // given
        `when`(callRepository.findById("not-exist")).thenReturn(Optional.empty())

        // when & then
        assertThrows<NoSuchElementException> {
            callService.endCall("not-exist", "user-A")
        }
    }

    // ────────────────────────────────────────────
    // cancelCall
    // ────────────────────────────────────────────

    @Test
    fun `should cancel call when caller cancels waiting call`() {
        // given
        val callId = "call-1"
        val callerId = "user-A"
        val call = CallEntity(id = callId, callerId = callerId, receiverId = "user-B", status = CallStatus.WAITING)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))
        `when`(callRepository.save(call)).thenReturn(call)

        // when
        val result = callService.cancelCall(callId, callerId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.CANCELLED)
    }

    @Test
    fun `should throw when receiver tries to cancel call`() {
        // given
        val callId = "call-1"
        val call = CallEntity(id = callId, callerId = "user-A", receiverId = "user-B", status = CallStatus.WAITING)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))

        // when & then
        val ex = assertThrows<IllegalArgumentException> {
            callService.cancelCall(callId, "user-B")
        }
        assertThat(ex.message).contains("발신자만")
    }

    @Test
    fun `should throw when cancelling active call`() {
        // given
        val callId = "call-1"
        val callerId = "user-A"
        val call = CallEntity(id = callId, callerId = callerId, receiverId = "user-B", status = CallStatus.ACTIVE)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))

        // when & then
        // ACTIVE 상태에서 취소 불가 (버그 재현: 진행 중 통화 취소 시도)
        assertThrows<IllegalStateException> {
