    @Test
    fun `should return empty list when user has no active calls`() {
        // given
        val userId = "user-Z"
        `when`(callRepository.findActiveCallsByUserId(userId)).thenReturn(emptyList())

        // when
        val result = callService.getActiveCallsForUser(userId)

        // then
        assertThat(result).isEmpty()
    }
}
