package com.maum.backend.domain.call

import jakarta.persistence.*
import java.time.LocalDateTime

@Entity
@Table(name = "calls")
class CallEntity(
    @Id
    @GeneratedValue(strategy = GenerationType.UUID)
    val id: String = "",

    @Column(nullable = false)
    val callerId: String,

    @Column(nullable = false)
    val receiverId: String,

    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    var status: CallStatus = CallStatus.WAITING,

    @Column
    var startedAt: LocalDateTime? = null,

    @Column
    var endedAt: LocalDateTime? = null,

    @Column(nullable = false)
    val createdAt: LocalDateTime = LocalDateTime.now(),
) {
    fun start() {
        check(status == CallStatus.WAITING) { "통화는 WAITING 상태에서만 시작할 수 있습니다. 현재 상태: $status" }
        status = CallStatus.ACTIVE
        startedAt = LocalDateTime.now()
    }

    fun end() {
        check(status == CallStatus.ACTIVE) { "통화는 ACTIVE 상태에서만 종료할 수 있습니다. 현재 상태: $status" }
        status = CallStatus.ENDED
        endedAt = LocalDateTime.now()
    }

    fun fail() {
        check(status == CallStatus.WAITING || status == CallStatus.ACTIVE) {
            "WAITING 또는 ACTIVE 상태에서만 실패 처리할 수 있습니다. 현재 상태: $status"
        }
        status = CallStatus.FAILED
        endedAt = LocalDateTime.now()
    }

    fun cancel() {
        check(status == CallStatus.WAITING) { "통화는 WAITING 상태에서만 취소할 수 있습니다. 현재 상태: $status" }
        status = CallStatus.CANCELLED
    }

    fun durationSeconds(): Long? {
        return if (startedAt != null && endedAt != null) {
            java.time.Duration.between(startedAt, endedAt).seconds
        } else null
    }
}
