package com.maum.backend.service

import com.maum.backend.domain.call.CallEntity
import com.maum.backend.domain.call.CallRepository
import com.maum.backend.domain.call.CallStatus
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
class CallService(
    private val callRepository: CallRepository,
) {
    @Transactional
    fun initiateCall(callerId: String, receiverId: String): CallEntity {
        require(callerId.isNotBlank()) { "callerId는 비어있을 수 없습니다." }
        require(receiverId.isNotBlank()) { "receiverId는 비어있을 수 없습니다." }
        require(callerId != receiverId) { "자기 자신에게 전화할 수 없습니다." }

        // 중복 통화 확인
        val existingCalls = callRepository.findActiveCallsByUserId(callerId)
        if (existingCalls.isNotEmpty()) {
            throw IllegalStateException("이미 진행 중인 통화가 있습니다.")
        }

        val call = CallEntity(callerId = callerId, receiverId = receiverId)
        return callRepository.save(call)
    }

    @Transactional
    fun acceptCall(callId: String, userId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { NoSuchElementException("통화를 찾을 수 없습니다: $callId") }

        require(call.receiverId == userId) { "수신자만 통화를 수락할 수 있습니다." }

        call.start()
        return callRepository.save(call)
    }

    @Transactional
    fun endCall(callId: String, userId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { NoSuchElementException("통화를 찾을 수 없습니다: $callId") }

        require(call.callerId == userId || call.receiverId == userId) {
            "통화 참여자만 종료할 수 있습니다."
        }

        call.end()
        return callRepository.save(call)
    }

    @Transactional
    fun cancelCall(callId: String, userId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { NoSuchElementException("통화를 찾을 수 없습니다: $callId") }

        require(call.callerId == userId) { "발신자만 통화를 취소할 수 있습니다." }

        call.cancel()
        return callRepository.save(call)
    }

    @Transactional
    fun failCall(callId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { NoSuchElementException("통화를 찾을 수 없습니다: $callId") }

        call.fail()
        return callRepository.save(call)
    }

    @Transactional(readOnly = true)
    fun getCall(callId: String): CallEntity {
        return callRepository.findById(callId)
            .orElseThrow { NoSuchElementException("통화를 찾을 수 없습니다: $callId") }
    }

    @Transactional(readOnly = true)
    fun getActiveCallsForUser(userId: String): List<CallEntity> {
        return callRepository.findActiveCallsByUserId(userId)
    }
}
