        // ACTIVE 상태에서 취소 불가 (버그 재현: 진행 중 통화 취소 시도)
        assertThrows<IllegalStateException> {
            callService.cancelCall(callId, callerId)
        }
    }

    // ────────────────────────────────────────────
    // failCall
    // ────────────────────────────────────────────

    @Test
    fun `should fail call when call is in waiting state`() {
        // given
        val callId = "call-1"
        val call = CallEntity(id = callId, callerId = "user-A", receiverId = "user-B", status = CallStatus.WAITING)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))
        `when`(callRepository.save(call)).thenReturn(call)

        // when
        val result = callService.failCall(callId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.FAILED)
        assertThat(result.endedAt).isNotNull()
    }

    @Test
    fun `should fail call when call is in active state`() {
        // given
        val callId = "call-1"
        val call = CallEntity(id = callId, callerId = "user-A", receiverId = "user-B", status = CallStatus.ACTIVE)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))
        `when`(callRepository.save(call)).thenReturn(call)

        // when
        val result = callService.failCall(callId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.FAILED)
    }

    @Test
    fun `should throw when failing already ended call`() {
        // given
        val callId = "call-1"
        val call = CallEntity(id = callId, callerId = "user-A", receiverId = "user-B", status = CallStatus.ENDED)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))

        // when & then
        assertThrows<IllegalStateException> {
            callService.failCall(callId)
        }
    }

    // ────────────────────────────────────────────
    // getActiveCallsForUser
    // ────────────────────────────────────────────

    @Test
    fun `should return active calls for user`() {
        // given
