        `when`(callRepository.findActiveCallsByUserId(userId)).thenReturn(activeCalls)

        // when
        val result = callService.getActiveCallsForUser(userId)

        // then
        assertThat(result).hasSize(1)
        assertThat(result[0].callerId).isEqualTo(userId)
        verify(callRepository).findActiveCallsByUserId(userId)
    }

    @Test
    fun `should return empty list when user has no active calls`() {
