**CallGrpcServiceTest.kt (gRPC 레이어 테스트)**
```kotlin
package com.maum.backend.controller

import com.maum.backend.domain.call.CallEntity
import com.maum.backend.domain.call.CallStatus
import com.maum.backend.service.CallService
import com.maum.backend.protobuf.call.*
import io.grpc.Status
import io.grpc.StatusRuntimeException
import io.grpc.stub.StreamObserver
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.*
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import org.mockito.kotlin.argumentCaptor

@ExtendWith(MockitoExtension::class)
class CallGrpcServiceTest {

    @Mock
    private lateinit var callService: CallService

    @InjectMocks
    private lateinit var callGrpcService: CallGrpcService

    @Test
    fun `should initiate call and respond via gRPC`() {
        // given
        val request = InitiateCallRequest.newBuilder()
            .setCallerId("user-A")
            .setReceiverId("user-B")
            .build()
        val responseObserver = mock<StreamObserver<InitiateCallResponse>>()
        val call = CallEntity(id = "call-1", callerId = "user-A", receiverId = "user-B")

        `when`(callService.initiateCall("user-A", "user-B")).thenReturn(call)

        // when
        callGrpcService.initiateCall(request, responseObserver)

        // then
        verify(responseObserver).onNext(any())
        verify(responseObserver).onCompleted()
        verify(responseObserver, never()).onError(any())
    }

    @Test
    fun `should propagate error when initiateCall fails in gRPC`() {
        // given
        val request = InitiateCallRequest.newBuilder()
            .setCallerId("user-A")
            .setReceiverId("user-A") // 자기 자신 호출 → 에러
            .build()
        val responseObserver = mock<StreamObserver<InitiateCallResponse>>()

        `when`(callService.initiateCall(any(), any()))
            .thenThrow(IllegalArgumentException("자기 자신에게 전화할 수 없습니다."))

        // when
        callGrpcService.initiateCall(request, responseObserver)

        // then
        verify(responseObserver, never()).onNext(any())
        verify(responseObserver, never()).onCompleted()
        verify(responseObserver).onError(any<StatusRuntimeException>())
    }

    @Test
    fun `should end call and respond via gRPC`() {
        // given
        val request = EndCallRequest.newBuilder()
            .setCallId("call-1")
            .setUserId("user-A")
            .build()
        val responseObserver = mock<StreamObserver<EndCallResponse>>()
        val call = CallEntity(id = "call-1", callerId = "user-A", receiverId = "user-B", status = CallStatus.ENDED)

        `when`(callService.endCall("call-1", "user-A")).thenReturn(call)

        // when
        callGrpcService.endCall(request, responseObserver)

        // then
        verify(responseObserver).onNext(any())
        verify(responseObserver).onCompleted()
        verify(responseObserver, never()).onError(any())
    }

    @Test
    fun `should return NOT_FOUND when call does not exist in gRPC`() {
        // given
        val request = EndCallRequest.newBuilder()
            .setCallId("not-exist")
            .setUserId("user-A")
            .build()
        val responseObserver = mock<StreamObserver<EndCallResponse>>()

        `when`(callService.endCall("not-exist", "user-A"))
            .thenThrow(NoSuchElementException("통화를 찾을 수 없습니다: not-exist"))

        // when
        callGrpcService.endCall(request, responseObserver)

        // then
        val captor = argumentCaptor<Throwable>()
        verify(responseObserver).onError(captor.capture())
        val error = captor.firstValue as StatusRuntimeException
        assert(error.status.code == Status.NOT_FOUND.code)
    }
}
